def _batch_values(
    values: cabc.Iterable[V], batch_size: int
) -> cabc.Iterator[tuple[V, ...]]:
    """Split ``values`` into chunks of at most ``batch_size`` items,
    preserving a final chunk that is smaller than ``batch_size``.
    """
    it = iter(values)

    while True:
        chunk = tuple(islice(it, batch_size))

        if not chunk:
            return

        yield chunk

